'use strict';

// Semantic-version precedence sorting. See docs/registry.md for the contract
// and docs/conventions.md for the precedence rules (numeric core fields,
// pre-release lower than release, build metadata ignored for precedence).
//
// Returns the input version strings sorted ascending by SemVer precedence,
// each original string preserved verbatim (build metadata is not stripped),
// without mutating the input array.

function parseSemVer(version) {
  // Strip build metadata for comparison purposes
  const [versionWithoutBuild] = version.split('+');
  const [corePart, ...preParts] = versionWithoutBuild.split('-');
  const preRelease = preParts.join('-');
  const [major, minor, patch] = corePart.split('.').map(Number);
  return { major, minor, patch, preRelease };
}

function comparePreRelease(a, b) {
  // No pre-release means higher precedence than having one
  if (a === '' && b === '') return 0;
  if (a === '') return 1;
  if (b === '') return -1;

  const aIds = a.split('.');
  const bIds = b.split('.');
  const len = Math.min(aIds.length, bIds.length);

  for (let i = 0; i < len; i++) {
    const aId = aIds[i];
    const bId = bIds[i];
    const aIsNum = /^\d+$/.test(aId);
    const bIsNum = /^\d+$/.test(bId);

    if (aIsNum && bIsNum) {
      const diff = Number(aId) - Number(bId);
      if (diff !== 0) return diff;
    } else {
      // Numeric identifiers always have lower precedence than alphanumeric
      if (aIsNum) return -1;
      if (bIsNum) return 1;
      if (aId < bId) return -1;
      if (aId > bId) return 1;
    }
  }

  // Larger set of fields has higher precedence
  return aIds.length - bIds.length;
}

function compareVersions(a, b) {
  const pa = parseSemVer(a);
  const pb = parseSemVer(b);

  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;

  return comparePreRelease(pa.preRelease, pb.preRelease);
}

function sortVersions(versions) {
  return versions.slice().sort(compareVersions);
}

